  ('aboriginal-6f0ba476-moex-00020', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'X1年初甲公司銷貨予乙公司，產生一筆應收分期帳款，乙公司除頭期款$250,000外，X1年至X3 年每年底需支付$250,000，有效利率10%。X1年底甲公司於收到乙公司款項$250,000後，評估乙 公司信用風險已顯著增加，估計預期信用風險損失金額為$54,545。試問甲公司X2年認列之利息 收入金額？（3期，利率10%，$1普通年金現值＝2.486852）', '["$25,000", "$37,934", "$43,388", "$50,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00021', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司向銀行借款$1,000,000，利率8%，借期6個月，銀行要求借款期間甲公司於該銀行存款金 額需達$200,000，銀行提供存款利率2%。該筆借款之實質借款年利率為多少？', '["4.75%", "6%", "8%", "9.5%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00022', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司倉庫於 6 月 30 日遭受火災，導致存貨全部損毀，已知 6 月份期初存貨為$600,000，進貨為 $900,000，銷貨收入為$1,800,000，估計毛利率為30%。若採毛利法估計，甲公司之火災損失金額為何？', '["$180,000", "$200,000", "$220,000", "$240,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00023', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初購入成本$500,000設備，估計耐用年限10年，無殘值，採直線法提列折舊，後 續衡量採用重估價模式，並採累積折舊沖轉至成本法之會計處理。該設備於使用期間未出現減損 跡象，殘值及耐用年限亦均未改變。該設備於X1年底進行重估價，公允價值為$540,000。假設該 公司選擇重估增值不隨折舊比例轉列保留盈餘，則 X1 年底甲公司認列之其他綜合損益與 X2 年 之折舊費用金額分別為多少？', '["$90,000與$60,000", "$50,000與$60,000", "$90,000與$50,000", "$40,000與$90,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00024', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列何者不屬於「其他綜合損益－不重分類至損益之項目」？', '["確定福利計畫之再衡量數", "透過其他綜合損益按公允價值衡量之債務工具投資評價損益", "不動產重估增值", "透過其他綜合損益按公允價值衡量之權益工具投資評價損益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00025', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '關於投資性不動產之會計處理，下列敘述何者錯誤？', '["原始認列後，企業得選擇按成本模式或公允價值模式進行後續衡量", "選擇按公允價值衡量之投資性不動產，應將公允價值變動認列為當期損益", "選擇按公允價值衡量之投資性不動產應於每年底提列折舊", "企業若判定無法在持續基礎上，可靠衡量投資性不動產之公允價值，則應依IAS16之成本模式 衡量投資性不動產，並假設殘值為零"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00026', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列關於生物資產與農業產品會計處理，何者錯誤？', '["動物園所飼養供觀賞用之動物，不適用IAS41所規定之農業會計處理", "生物資產可區分為生產性動物、消耗性動物、生產性植物、消耗性植物", "IAS41規定，在所有的情況下企業於農業產品收成點，均應以其公允價值減出售成本衡量", "消耗性植物之會計處理應依IAS16比照固定資產以成本模式或重估價模式處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00027', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列有關財務報表要素衡量之敘述，何者正確？', '["企業應就所有資產與負債選擇一共同衡量基礎，以使財務報表編製有一致的衡量基礎", "就資產之衡量而言，歷史成本係指於取得資產時，所支付之對價加上交易成本後之價值", "就負債之衡量而言，現時成本係就約當負債於衡量日將收取之對價加上將發生之交易成本", "財務報表要素之衡量基礎，一經決定即不可改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00028', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲想以新臺幣（下同）600 萬元，向乙購買土地一筆，欲自地建屋。土
